firmware_template.source:
#include "mcp3008.h"
#include <SPI.h>
#include <Adafruit_MCP3008.h>
static Adafruit_MCP3008 adc;
void mcp3008_setup(){adc.begin(5);Serial.println("[mcp3008] OK 8ch 10bit");}
int mcp3008_read(uint8_t c){return adc.readADC(c);}
float mcp3008_read_voltage(uint8_t c){return adc.readADC(c)*3.3/1023.0;}
